commands.cmd:
total=$(ps -e --no-headers 2>/dev/null | wc -l) || { echo "ps failed" >&2; exit 1; }
[ "$total" -gt 0 ] || { echo "ps returned no processes" >&2; exit 1; }
pid_max=$(cat /proc/sys/kernel/pid_max) || { echo "pid_max unreadable" >&2; exit 1; }
awk -v t="$total" -v m="$pid_max" 'BEGIN{
  printf "{\"total\":%d,\"pid_max\":%d,\"used_pct\":\"%.1f\"}", t, m, (m>0 ? t/m*100 : 0)
}' || exit 1
